workflow {
  Channel.fromFilePairs(params.reads) | QC | ASSEMBLE | BIN | CHECKM
}
// Cite: https://nf-co.re/mag

workflow {
  READS | QC | TAXONOMY_PARALLEL(kraken2, metaphlan) | MERGE_PROFILES
}
// Cite: https://nf-co.re/taxprofiler

process VIWRAP {
  input: path reads
  output: path 'virus_bins'
  script: "ViWrap -i $reads -o virus_bins"
}
